TIERS = ["Chat", "CoWork", "Claude Code", "Human-only"]

def classify_task(task: str, signals: list[str]) -> dict:
    """Classify a task using the routing signal set."""
    has_production = any("production" in s.lower() for s in signals)
    has_regulated = any("regulated" in s.lower() or "hipaa" in s.lower() for s in signals)
    has_irreversible = any("irreversible" in s.lower() for s in signals)
    is_multistep = any("multi-step" in s.lower() for s in signals)

    if has_regulated or has_irreversible:
        tier = "Human-only"
    elif has_production or is_multistep:
        tier = "CoWork"
    elif any("autonomous" in s.lower() for s in signals):
        tier = "Claude Code"
    else:
        tier = "Chat"

    key_signal = signals[0] if signals else "none"
    confidence = 0.9 if len(signals) >= 2 else 0.7
    return {"task": task, "tier": tier, "key_signal": key_signal,
            "confidence": confidence}
